from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

# Database connection parameters
DB_HOST = 'your_db_host'
DB_NAME = 'your_db_name'
DB_USER = 'your_db_user'
DB_PASSWORD = 'your_db_password'

def get_db_connection():
    conn = psycopg2.connect(host=DB_HOST, database=DB_NAME, user=DB_USER, password=DB_PASSWORD)
    conn.cursor_factory = RealDictCursor
    return conn

@app.route('/query', methods=['GET'])
def query_data():
    table_name = request.args.get('table')
    columns = request.args.get('columns')
    filter_condition = request.args.get('filter')

    if not all([table_name, columns]):
        return jsonify({'error': 'Missing required parameters'}), 400

    # Sanitize input to prevent SQL injection
    table_name = psycopg2.extensions.adapt(table_name).getquoted().decode()
    columns = [psycopg2.extensions.adapt(col).getquoted().decode() for col in columns.split(',')]
    filter_condition = psycopg2.extensions.adapt(filter_condition).getquoted().decode()

    query = f"SELECT {', '.join(columns)} FROM {table_name}"
    if filter_condition:
        query += f" WHERE {filter_condition}"

    try:
        conn = get_db_connection()
        cur = conn.cursor()
        cur.execute(query)
        results = cur.fetchall()
        cur.close()
        conn.close()
        return jsonify(results), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)